import{_ as t,o as a,c as o,ai as i}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Menu Bar Icon","description":"","frontmatter":{"summary":"Menu bar icon states and animations for OpenSoul on macOS","read_when":["Changing menu bar icon behavior"],"title":"Menu Bar Icon"},"headers":[],"relativePath":"platforms/mac/icon.md","filePath":"platforms/mac/icon.md","lastUpdated":null}'),r={name:"platforms/mac/icon.md"};function n(s,e,l,c,d,g){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="menu-bar-icon-states" tabindex="-1"><a class="header-anchor" href="#menu-bar-icon-states">#</a> Menu Bar Icon States</h1><p>Author: steipete · Updated: 2025-12-06 · Scope: macOS app (<code>apps/macos</code>)</p><ul><li><strong>Idle:</strong> Normal icon animation (blink, occasional wiggle).</li><li><strong>Paused:</strong> Status item uses <code>appearsDisabled</code>; no motion.</li><li><strong>Voice trigger (big ears):</strong> Voice wake detector calls <code>AppState.triggerVoiceEars(ttl: nil)</code> when the wake word is heard, keeping <code>earBoostActive=true</code> while the utterance is captured. Ears scale up (1.9x), get circular ear holes for readability, then drop via <code>stopVoiceEars()</code> after 1s of silence. Only fired from the in-app voice pipeline.</li><li><strong>Working (agent running):</strong> <code>AppState.isWorking=true</code> drives a “tail/leg scurry” micro-motion: faster leg wiggle and slight offset while work is in-flight. Currently toggled around WebChat agent runs; add the same toggle around other long tasks when you wire them.</li></ul><p>Wiring points</p><ul><li>Voice wake: runtime/tester call <code>AppState.triggerVoiceEars(ttl: nil)</code> on trigger and <code>stopVoiceEars()</code> after 1s of silence to match the capture window.</li><li>Agent activity: set <code>AppStateStore.shared.setWorking(true/false)</code> around work spans (already done in WebChat agent call). Keep spans short and reset in <code>defer</code> blocks to avoid stuck animations.</li></ul><p>Shapes &amp; sizes</p><ul><li>Base icon drawn in <code>CritterIconRenderer.makeIcon(blink:legWiggle:earWiggle:earScale:earHoles:)</code>.</li><li>Ear scale defaults to <code>1.0</code>; voice boost sets <code>earScale=1.9</code> and toggles <code>earHoles=true</code> without changing overall frame (18×18 pt template image rendered into a 36×36 px Retina backing store).</li><li>Scurry uses leg wiggle up to ~1.0 with a small horizontal jiggle; it’s additive to any existing idle wiggle.</li></ul><p>Behavioral notes</p><ul><li>No external CLI/broker toggle for ears/working; keep it internal to the app’s own signals to avoid accidental flapping.</li><li>Keep TTLs short (&lt;10s) so the icon returns to baseline quickly if a job hangs.</li></ul>',9)])])}const h=t(r,[["render",n]]);export{u as __pageData,h as default};
